<html>
<head>
<title>Text Input Form</title>
</head>
<body>

<form id="textForm">
  <label for="textInput">Enter text:</label>
  <textarea id="textInput" name="textInput" rows="4" cols="50"></textarea><br><br>
  <input type="submit" value="Save Text">
</form>

<script>
  document.getElementById('textForm').addEventListener('submit', function(event) {
    event.preventDefault();
    const textInput = document.getElementById('textInput');
    const text = textInput.value;

    // In a real application, you would send this data to a server to save it.
    // For this example, we'll just log it to the console.
    console.log("Text saved:", text);

    alert("Text saved successfully! Check the console for the content.");

    // Optionally clear the input field after saving
    textInput.value = '';
  });
</script>

</body>
</html>
